// ============ GitHub 风格 callouts ============
// 用法：> [!NOTE] / [!TIP] / [!IMPORTANT] / [!WARNING] / [!CAUTION]
.docs-content {
  .markdown-alert {
    margin: 16px 0;
    padding: 12px 16px;
    border-left: 4px solid currentColor;
    border-radius: 0 6px 6px 0;
    background: $bg-soft;

    & > *:first-child { margin-top: 0; }
    & > *:last-child { margin-bottom: 0; }

    p { margin: 6px 0; }
  }

  .markdown-alert-title {
    display: flex;
    align-items: center;
    gap: 8px;
    margin-bottom: 4px;
    font-weight: 600;
    font-size: 14px;

    svg {
      width: 16px;
      height: 16px;
      flex-shrink: 0;
    }
  }

  .markdown-alert-note {
    color: #1f5fb3;
    background: rgba\(31, 95, 179, 0.06\);
    border-left-color: #1f5fb3;
  }
  .markdown-alert-tip {
    color: #1a7d3d;
    background: rgba\(26, 125, 61, 0.06\);
    border-left-color: #1a7d3d;
  }
  .markdown-alert-important {
    color: #7c3aed;
    background: rgba\(124, 58, 237, 0.06\);
    border-left-color: #7c3aed;
  }
  .markdown-alert-warning {
    color: #9a6700;
    background: rgba\(154, 103, 0, 0.08\);
    border-left-color: #d4a72c;
  }
  .markdown-alert-caution {
    color: #b3241d;
    background: rgba\(179, 36, 29, 0.06\);
    border-left-color: #b3241d;
  }
}
EOF)
